public int translate(CharSequence input, int index, Writer out) throws IOException {
    if (input == null || out == null || index < 0 || index >= input.length()) {
        throw new IllegalArgumentException("Invalid input or output provided.");
    }

    if (index + 1 < input.length() && input.charAt(index) == '&' && input.charAt(index + 1) == '#') {
        int start = index + 2;
        boolean isHex = false;

        if (start < input.length()) {
            char firstChar = input.charAt(start);
            if (firstChar == 'x' || firstChar == 'X') {
                start++;
                isHex = true;
            }
        }

        int end = start;
        while (end < input.length() && input.charAt(end) != ';') {
            end++;
        }

        if (end >= input.length() || input.charAt(end) != ';') {
            return 0; // no terminating semicolon, not a valid entity
        }

        int entityValue;
        try {
            if (isHex) {
                entityValue = Integer.parseInt(input.subSequence(start, end).toString(), 16);
            } else {
                entityValue = Integer.parseInt(input.subSequence(start, end).toString(), 10);
            }
        } catch (NumberFormatException nfe) {
            return 0;
        }

        if (Character.isSupplementaryCodePoint(entityValue)) {
            char[] chars = Character.toChars(entityValue);
            out.write(chars);
        } else {
            out.write(entityValue);
        }

        return 2 + (end - start) + (isHex ? 1 : 0) + 1; // 2 for "&#", end-start for entity, 1 if hex (x or X), 1 for ";"
    }
    return 0;
}

